1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Step = QuoteStep;
10	
11	export type Scenario = {
12	  customer: { yearsWithMHPCO: number };
13	  steps: Step[];
14	};
15	
16	export type QuoteResult = { premium: number };
17	export type StepResult = QuoteResult;
18	export type ScenarioResult = { results: StepResult[] };
19	
20	const PROCESSING_FEE = 5;
21	// Premiums are accumulated in tenths of a gold piece so we can apply
22	// fractional surcharges/discounts with integer math and round once at the end
23	// (avoids floating-point artifacts like 100 * 1.1 = 110.00000000000001).
24	const TENTHS_PER_UNIT = 10;
25	const FIRST_INSURANCE_TENTHS = 1;
26	
27	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
28	  sword: 100,
29	  amulet: 60,
30	  staff: 80,
31	  potion: 40,
32	  rune: 25,
33	  moonstone: 25,
34	};
35	
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	const BLOCK_SIZE = 3;
38	const BLOCK_BASE_PREMIUM = 60;
39	
40	const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
41	
42	const sumBasePremiums = (items: Item[]): number =>
43	  items.reduce((sum, item) => sum + basePremium(item), 0);
44	
45	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
46	
47	const groupByType = (items: Item[]): Item[][] => {
48	  const groups: Record<string, Item[]> = {};
49	  for (const item of items) {
50	    (groups[item.type] ??= []).push(item);
51	  }
52	  return Object.values(groups);
53	};
54	
55	const componentGroupBasePremium = (group: Item[]): number =>
56	  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);
57	
58	const itemsBasePremium = (items: Item[]): number => {
59	  const components = items.filter(isComponent);
60	  const mains = items.filter((item) => !isComponent(item));
61	  const componentTotal = groupByType(components)
62	    .map(componentGroupBasePremium)
63	    .reduce((sum, premium) => sum + premium, 0);
64	  return sumBasePremiums(mains) + componentTotal;
65	};
66	
67	const roundUpTenthsToUnits = (tenths: number): number => Math.ceil(tenths / TENTHS_PER_UNIT);
68	
69	const CURSE_TENTHS = 5;
70	
71	const itemSurchargesTenths = (items: Item[]): number =>
72	  items.reduce((sum, item) => {
73	    let tenths = 0;
74	    if (item.cursed) tenths += basePremium(item) * CURSE_TENTHS;
75	    return sum + tenths;
76	  }, 0);
77	
78	const quote = (step: QuoteStep): QuoteResult => {
79	  const baseTotal = itemsBasePremium(step.items);
80	  const baseTenths = baseTotal * TENTHS_PER_UNIT;
81	  const itemSurcharge = itemSurchargesTenths(step.items);
82	  const firstInsurance = baseTotal * FIRST_INSURANCE_TENTHS;
83	  const totalTenths = baseTenths + itemSurcharge + firstInsurance;
84	  return { premium: roundUpTenthsToUnits(totalTenths) + PROCESSING_FEE };
85	};
86	
87	export const runScenario = (scenario: Scenario): ScenarioResult => {
88	  return { results: scenario.steps.map(quote) };
89	};
