const roundUpTenthsToUnits = (tenths: number): number => Math.ceil(tenths / TENTHS_PER_UNIT);

// Item-specific modifiers expressed as +N tenths-per-gold-base (additive).
const CURSE_SURCHARGE_TENTHS = 5; // +50%

const itemModifierTenths = (item: Item): number =>
  (item.cursed ? CURSE_SURCHARGE_TENTHS : 0);

// Policy-wide modifiers (applied per gold of total base premium).
const FIRST_QUOTE_MODIFIER_TENTHS = FIRST_INSURANCE_TENTHS; // +10%

const itemPremiumTenths = (item: Item, baseGold: number): number =>
  baseGold * (TENTHS_PER_UNIT + itemModifierTenths(item));

const policyModifierTenths = (totalBaseGold: number): number =>
  totalBaseGold * FIRST_QUOTE_MODIFIER_TENTHS;

const quote = (step: QuoteStep): QuoteResult => {
  const itemBaseGolds = itemBasePremiums(step.items);
  const totalBaseGold = itemBaseGolds.reduce((sum, gold) => sum + gold, 0);
  const itemContributions = step.items
    .map((item, i) => itemPremiumTenths(item, itemBaseGolds[i]))
    .reduce((sum, tenths) => sum + tenths, 0);
  const totalTenths = itemContributions + policyModifierTenths(totalBaseGold);
  return { premium: roundUpTenthsToUnits(totalTenths) + PROCESSING_FEE };
};

